def evaluate(self, *args, **kw):
    op = self.op
    args, kw = self._get_kwarg_model_parameters_as_positional(args, kw)
    left_inputs = self._get_left_inputs_from_args(args)
    left_params = self._get_left_params_from_args(args)

    if op == 'fix_inputs':
        pos_index = dict(zip(self.left.inputs, range(self.left.n_inputs)))
        fixed_inputs = {
            key if np.issubdtype(type(key), np.integer) else pos_index[key]: value
            for key, value in self.right.items()
        }
        left_inputs = [
            fixed_inputs[ind] if ind in fixed_inputs.keys() else inp
            for ind, inp in enumerate(left_inputs)
        ]

    leftval = self.left.evaluate(*itertools.chain(left_inputs, left_params))

    if op == 'fix_inputs':
        return leftval

    right_inputs = self._get_right_inputs_from_args(args)
    right_params = self._get_right_params_from_args(args)

    if op == "|":
        if isinstance(leftval, tuple):
            return self.right.evaluate(*itertools.chain(leftval, right_params))
        else:
            return self.right.evaluate(leftval, *right_params)
    else:
        rightval = self.right.evaluate(*itertools.chain(right_inputs, right_params))

    return self._apply_operators_to_value_lists(leftval, rightval, **kw)

def n_inputs(self):
    """ The number of inputs of a model."""
    return self._n_inputs

def n_outputs(self):
    """ The number of outputs of a model."""
    return self._n_outputs

def deconstruct(self):
    kwargs = {
        'model_name': self.model_name,
        'name': self.name,
        'field': self.field,
    }
    if self.preserve_default is not True:
        kwargs['preserve_default'] = self.preserve_default
    return (
        self.__class__.__name__,
        [],
        kwargs
    )

def from_model(cls, model, exclude_rels=False):
    """Given a model, return a ModelState representing it."""
    # Deconstruct the fields
    fields = []
    for field in model._meta.local_fields:
        if getattr(field, "remote_field", None) and exclude_rels:
            continue
        if isinstance(field, OrderWrt):
            continue
        name = field.name
        try:
            fields.append((name, field.clone()))
        except TypeError as e:
            raise TypeError("Couldn't reconstruct field %s on %s: %s" % (
                name,
                model._meta.label,
                e,
            ))
    if not exclude_rels:
        for field in model._meta.local_many_to_many:
            name = field.name
            try:
                fields.append((name, field.clone()))
            except TypeError as e:
                raise TypeError("Couldn't reconstruct m2m field %s on %s: %s" % (
                    name,
                    model._meta.object_name,
                    e,
                ))
    # Extract the options
    options = {}
    for name in DEFAULT_NAMES:
        # Ignore some special options
        if name in ["apps", "app_label"]:
            continue
        elif name in model._meta.original_attrs:
            if name == "unique_together":
                ut = model._meta.original_attrs["unique_together"]
                options[name] = set(normalize_together(ut))
            elif name == "index_together":
                it = model._meta.original_attrs["index_together"]
                options[name] = set(normalize_together(it))
            elif name == "indexes":
                indexes = [idx.clone() for idx in model._meta.indexes]
                for index in indexes:
                    if not index.name:
                        index.set_name_with_model(model)
                options['indexes'] = indexes
            elif name == 'constraints':
                options['constraints'] = [con.clone() for con in model._meta.constraints]
            else:
                options[name] = model._meta.original_attrs[name]
    # If we're ignoring relationships, remove all field-listing model
    # options (that option basically just means "make a stub model")
    if exclude_rels:
        for key in ["unique_together", "index_together", "order_with_respect_to"]:
            if key in options:
                del options[key]
    # Private fields are ignored, so remove options that refer to them.
    elif options.get('order_with_respect_to') in {field.name for field in model._meta.private_fields}:
        del options['order_with_respect_to']

    def flatten_bases(model):
        bases = []
        for base in model.__bases__:
            if hasattr(base, "_meta") and base._meta.abstract:
                bases.extend(flatten_bases(base))
            else:
                bases.append(base)
        return bases

    # We can't rely on __mro__ directly because we only want to flatten
    # abstract models and not the whole tree. However by recursing on
    # __bases__ we may end up with duplicates and ordering issues, we
    # therefore discard any duplicates and reorder the bases according
    # to their index in the MRO.
    flattened_bases = sorted(set(flatten_bases(model)), key=lambda x: model.__mro__.index(x))

    # Make our record
    bases = tuple(
        (
            base._meta.label_lower
            if hasattr(base, "_meta") else
            base
        )
        for base in flattened_bases
    )
    # Ensure at least one base inherits from models.Model
    if not any((isinstance(base, str) or issubclass(base, models.Model)) for base in bases):
        bases = (models.Model,)

    managers = []
    manager_names = set()
    default_manager_shim = None
    for manager in model._meta.managers:
        if manager.name in manager_names:
            # Skip overridden managers.
            continue
        elif manager.use_in_migrations:
            # Copy managers usable in migrations.
            new_manager = copy.copy(manager)
            new_manager._set_creation_counter()
        elif manager is model._base_manager or manager is model._default_manager:
            # Shim custom managers used as default and base managers.
            new_manager = models.Manager()
            new_manager.model = manager.model
            new_manager.name = manager.name
            if manager is model._default_manager:
                default_manager_shim = new_manager
        else:
            continue
        manager_names.add(manager.name)
        managers.append((manager.name, new_manager))

    # Ignore a shimmed default manager called objects if it's the only one.
    if managers == [('objects', default_manager_shim)]:
        managers = []

    # Construct the new ModelState
    return cls(
        model._meta.app_label,
        model._meta.object_name,
        fields,
        options,
        bases,
        managers,
    )

def deconstruct(self):
    kwargs = {
        'model_name': self.model_name,
        'name': self.name,
        'field': self.field,
    }
    if self.preserve_default is not True:
        kwargs['preserve_default'] = self.preserve_default
    return (
        self.__class__.__name__,
        [],
        kwargs
    )

def delete(self, using=None, keep_parents=False):
    using = using or router.db_for_write(self.__class__, instance=self)
    assert self.pk is not None, (
        "%s object can't be deleted because its %s attribute is set to None." %
        (self._meta.object_name, self._meta.pk.attname)
    )

    collector = Collector(using=using)
    collector.collect([self], keep_parents=keep_parents)
    return collector.delete()

def delete(self):
    # sort instance collections
    for model, instances in self.data.items():
        self.data[model] = sorted(instances, key=attrgetter("pk"))

    # if possible, bring the models in an order suitable for databases that
    # don't support transactions or cannot defer constraint checks until the
    # end of a transaction.
    self.sort()
    # number of objects deleted for each model label
    deleted_counter = Counter()

    # Optimize for the case with a single obj and no dependencies
    if len(self.data) == 1 and len(instances) == 1:
        instance = list(instances)[0]
        if self.can_fast_delete(instance):
            with transaction.mark_for_rollback_on_error():
                count = sql.DeleteQuery(model).delete_batch([instance.pk], self.using)
            return count, {model._meta.label: count}

    with transaction.atomic(using=self.using, savepoint=False):
        # send pre_delete signals
        for model, obj in self.instances_with_model():
            if not model._meta.auto_created:
                signals.pre_delete.send(
                    sender=model, instance=obj, using=self.using
                )

        # fast deletes
        for qs in self.fast_deletes:
            count = qs._raw_delete(using=self.using)
            deleted_counter[qs.model._meta.label] += count

        # update fields
        for model, instances_for_fieldvalues in self.field_updates.items():
            for (field, value), instances in instances_for_fieldvalues.items():
                query = sql.UpdateQuery(model)
                query.update_batch([obj.pk for obj in instances],
                                   {field.name: value}, self.using)

        # reverse instance collections
        for instances in self.data.values():
            instances.reverse()

        # delete instances
        for model, instances in self.data.items():
            query = sql.DeleteQuery(model)
            pk_list = [obj.pk for obj in instances]
            count = query.delete_batch(pk_list, self.using)
            deleted_counter[model._meta.label] += count

            if not model._meta.auto_created:
                for obj in instances:
                    signals.post_delete.send(
                        sender=model, instance=obj, using=self.using
                    )

    # update collected instances
    for instances_for_fieldvalues in self.field_updates.values():
        for (field, value), instances in instances_for_fieldvalues.items():
            for obj in instances:
                setattr(obj, field.attname, value)
    for model, instances in self.data.items():
        for instance in instances:
            setattr(instance, model._meta.pk.attname, None)
    return sum(deleted_counter.values()), dict(deleted_counter)

def _get_pk_val(self, meta=None):
    meta = meta or self._meta
    return getattr(self, meta.pk.attname)

def sort(self):
    sorted_models = []
    concrete_models = set()
    models = list(self.data)
    while len(sorted_models) < len(models):
        found = False
        for model in models:
            if model in sorted_models:
                continue
            dependencies = self.dependencies.get(model._meta.concrete_model)
            if not (dependencies and dependencies.difference(concrete_models)):
                sorted_models.append(model)
                concrete_models.add(model._meta.concrete_model)
                found = True
        if not found:
            return
    self.data = {model: self.data[model] for model in sorted_models}

def instances_with_model(self):
    for model, instances in self.data.items():
        for obj in instances:
            yield model, obj

def resolve(self, path):
    path = str(path)  # path may be a reverse_lazy object
    tried = []
    match = self.pattern.match(path)
    if match:
        new_path, args, kwargs = match
        for pattern in self.url_patterns:
            try:
                sub_match = pattern.resolve(new_path)
            except Resolver404 as e:
                sub_tried = e.args[0].get('tried')
                if sub_tried is not None:
                    tried.extend([pattern] + t for t in sub_tried)
                else:
                    tried.append([pattern])
            else:
                if sub_match:
                    # Merge captured arguments in match with submatch
                    sub_match_dict = {**kwargs, **self.default_kwargs}
                    # Update the sub_match_dict with the kwargs from the sub_match.
                    sub_match_dict.update(sub_match.kwargs)
                    # If there are *any* named groups, ignore all non-named groups.
                    # Otherwise, pass all non-named arguments as positional arguments.
                    sub_match_args = sub_match.args
                    if not sub_match_dict:
                        sub_match_args = args + sub_match.args
                    current_route = '' if isinstance(pattern, URLPattern) else str(pattern.pattern)
                    return ResolverMatch(
                        sub_match.func,
                        sub_match_args,
                        sub_match_dict,
                        sub_match.url_name,
                        [self.app_name] + sub_match.app_names,
                        [self.namespace] + sub_match.namespaces,
                        self._join_route(current_route, sub_match.route),
                    )
                tried.append([pattern])
        raise Resolver404({'tried': tried, 'path': new_path})
    raise Resolver404({'path': path})

def resolve(self, path):
    match = self.pattern.match(path)
    if match:
        new_path, args, kwargs = match
        # Pass any extra_kwargs as **kwargs.
        kwargs.update(self.default_args)
        return ResolverMatch(self.callback, args, kwargs, self.pattern.name, route=str(self.pattern))

def match(self, path):
    match = self.regex.search(path)
    if match:
        # If there are any named groups, use those as kwargs, ignoring
        # non-named groups. Otherwise, pass all non-named arguments as
        # positional arguments.
        kwargs = {k: v for k, v in match.groupdict().items() if v is not None}
        args = () if kwargs else match.groups()
        return path[match.end():], args, kwargs
    return None

def match(self, path):
    match = self.regex.search(path)
    if match:
        # RoutePattern doesn't allow non-named groups so args are ignored.
        kwargs = match.groupdict()
        for key, value in kwargs.items():
            converter = self.converters[key]
            try:
                kwargs[key] = converter.to_python(value)
            except ValueError:
                return None
        return path[match.end():], (), kwargs
    return None

def match(self, path):
    language_prefix = self.language_prefix
    if path.startswith(language_prefix):
        return path[len(language_prefix):], (), {}
    return None

def _is_callback(self, name):
    if not self._populated:
        self._populate()
    return name in self._callback_strs

def _populate(self):
    # Short-circuit if called recursively in this thread to prevent
    # infinite recursion. Concurrent threads may call this at the same
    # time and will need to continue, so set 'populating' on a
    # thread-local variable.
    if getattr(self._local, 'populating', False):
        return
    try:
        self._local.populating = True
        lookups = MultiValueDict()
        namespaces = {}
        apps = {}
        language_code = get_language()
        for url_pattern in reversed(self.url_patterns):
            p_pattern = url_pattern.pattern.regex.pattern
            if p_pattern.startswith('^'):
                p_pattern = p_pattern[1:]
            if isinstance(url_pattern, URLPattern):
                self._callback_strs.add(url_pattern.lookup_str)
                bits = normalize(url_pattern.pattern.regex.pattern)
                lookups.appendlist(
                    url_pattern.callback,
                    (bits, p_pattern, url_pattern.default_args, url_pattern.pattern.converters)
                )
                if url_pattern.name is not None:
                    lookups.appendlist(
                        url_pattern.name,
                        (bits, p_pattern, url_pattern.default_args, url_pattern.pattern.converters)
                    )
            else:  # url_pattern is a URLResolver.
                url_pattern._populate()
                if url_pattern.app_name:
                    apps.setdefault(url_pattern.app_name, []).append(url_pattern.namespace)
                    namespaces[url_pattern.namespace] = (p_pattern, url_pattern)
                else:
                    for name in url_pattern.reverse_dict:
                        for matches, pat, defaults, converters in url_pattern.reverse_dict.getlist(name):
                            new_matches = normalize(p_pattern + pat)
                            lookups.appendlist(
                                name,
                                (
                                    new_matches,
                                    p_pattern + pat,
                                    {**defaults, **url_pattern.default_kwargs},
                                    {**self.pattern.converters, **url_pattern.pattern.converters, **converters}
                                )
                            )
                    for namespace, (prefix, sub_pattern) in url_pattern.namespace_dict.items():
                        current_converters = url_pattern.pattern.converters
                        sub_pattern.pattern.converters.update(current_converters)
                        namespaces[namespace] = (p_pattern + prefix, sub_pattern)
                    for app_name, namespace_list in url_pattern.app_dict.items():
                        apps.setdefault(app_name, []).extend(namespace_list)
                self._callback_strs.update(url_pattern._callback_strs)
        self._namespace_dict[language_code] = namespaces
        self._app_dict[language_code] = apps
        self._reverse_dict[language_code] = lookups
        self._populated = True
    finally:
        self._local.populating = False

def add_domain(domain, url, secure=False):
    protocol = 'https' if secure else 'http'
    if url.startswith('//'):
        # Support network-path reference (see #16753) - RSS requires a protocol
        url = '%s:%s' % (protocol, url)
    elif not url.startswith(('http://', 'https://', 'mailto:')):
        url = iri_to_uri('%s://%s%s' % (protocol, domain, url))
    return url

def item_extra_kwargs(self, item):
    """
    Return an extra keyword arguments dictionary that is used with
    the `add_item` call of the feed generator.
    """
    return {}

def item_title(self, item):
    # Titles should be double escaped by default (see #6533)
    return escape(str(item))

def item_link(self, item):
    try:
        return item.get_absolute_url()
    except AttributeError:
        raise ImproperlyConfigured(
            'Give your %s class a get_absolute_url() method, or define an '
            'item_link() method in your Feed class.' % item.__class__.__name__
        )

def item_enclosures(self, item):
    enc_url = self._get_dynamic_attr('item_enclosure_url', item)
    if enc_url:
        enc = feedgenerator.Enclosure(
            url=str(enc_url),
            length=str(self._get_dynamic_attr('item_enclosure_length', item)),
            mime_type=str(self._get_dynamic_attr('item_enclosure_mime_type', item)),
        )
        return [enc]
    return []

def _get_default_pk_class(self):
    pk_class_path = getattr(
        self.app_config,
        'default_auto_field',
        settings.DEFAULT_AUTO_FIELD,
    )
    if self.app_config and self.app_config._is_default_auto_field_overridden:
        app_config_class = type(self.app_config)
        source = (
            f'{app_config_class.__module__}.'
            f'{app_config_class.__qualname__}.default_auto_field'
        )
    else:
        source = 'DEFAULT_AUTO_FIELD'
    if not pk_class_path:
        raise ImproperlyConfigured(f'{source} must not be empty.')
    try:
        pk_class = import_string(pk_class_path)
    except ImportError as e:
        msg = (
            f"{source} refers to the module '{pk_class_path}' that could "
            f"not be imported."
        )
        raise ImproperlyConfigured(msg) from e
    if not issubclass(pk_class, AutoField):
        raise ValueError(
            f"Primary key '{pk_class_path}' referred by {source} must "
            f"subclass AutoField."
        )
    return pk_class

def get_related_field(self):
    """
    Return the field in the 'to' object to which this relationship is tied.
    Provided for symmetry with ManyToOneRel.
    """
    opts = self.through._meta
    if self.through_fields:
        field = opts.get_field(self.through_fields[0])
    else:
        for field in opts.fields:
            rel = getattr(field, 'remote_field', None)
            if rel and rel.model == self.model:
                break
    return field.foreign_related_fields[0]

def default(self, obj):
    if isinstance(obj, Message):
        # Using 0/1 here instead of False/True to produce more compact json
        is_safedata = 1 if isinstance(obj.message, SafeData) else 0
        message = [self.message_key, is_safedata, obj.level, obj.message]
        if obj.extra_tags:
            message.append(obj.extra_tags)
        return message
    return super().default(obj)

def decode(self, s, **kwargs):
    decoded = super().decode(s, **kwargs)
    return self.process_messages(decoded)

def process_messages(self, obj):
    if isinstance(obj, list) and obj:
        if obj[0] == MessageEncoder.message_key:
            if obj[1]:
                obj[3] = mark_safe(obj[3])
            return Message(*obj[2:])
        return [self.process_messages(item) for item in obj]
    if isinstance(obj, dict):
        return {key: self.process_messages(value)
                for key, value in obj.items()}
    return obj

def __eq__(self, other):
    if not isinstance(other, Message):
        return NotImplemented
    return self.level == other.level and self.message == other.message

def dumps(self, obj):
    return json.dumps(
        obj,
        separators=(',', ':'),
        cls=MessageEncoder,
    ).encode('latin-1')

def concrete_fields(self):
    """
    Return a list of all concrete fields on the model and its parents.

    Private API intended only to be used by Django itself; get_fields()
    combined with filtering of field properties is the public API for
    obtaining this field list.
    """
    return make_immutable_fields_list(
        "concrete_fields", (f for f in self.fields if f.concrete)
    )

def get_field(self, field_name):
    """
    Return a field instance given the name of a forward or reverse field.
    """
    try:
        # In order to avoid premature loading of the relation tree
        # (expensive) we prefer checking if the field is a forward field.
        return self._forward_fields_map[field_name]
    except KeyError:
        # If the app registry is not ready, reverse fields are
        # unavailable, therefore we throw a FieldDoesNotExist exception.
        if not self.apps.models_ready:
            raise FieldDoesNotExist(
                "%s has no field named '%s'. The app cache isn't ready yet, "
                "so if this is an auto-created related field, it won't "
                "be available yet." % (self.object_name, field_name)
            )

    try:
        # Retrieve field instance by name from cached or just-computed
        # field map.
        return self.fields_map[field_name]
    except KeyError:
        raise FieldDoesNotExist(
            "%s has no field named '%s'" % (self.object_name, field_name)
        )

def _fetch_all(self):
    if self._result_cache is None:
        self._result_cache = list(self._iterable_class(self))
    if self._prefetch_related_lookups and not self._prefetch_done:
        self._prefetch_related_objects()

def _iterator(self, use_chunked_fetch, chunk_size):
    iterable = self._iterable_class(
        self,
        chunked_fetch=use_chunked_fetch,
        chunk_size=chunk_size or 2000,
    )
    if not self._prefetch_related_lookups or chunk_size is None:
        yield from iterable
        return

    iterator = iter(iterable)
    while results := list(islice(iterator, chunk_size)):
        prefetch_related_objects(results, *self._prefetch_related_lookups)
        yield from results

def select_related(self, *fields):
    """
    Return a new QuerySet instance that will select related objects.

    If fields are specified, they must be ForeignKey fields and only those
    related objects are included in the selection.

    If select_related(None) is called, clear the list.
    """
    self._not_support_combined_queries("select_related")
    if self._fields is not None:
        raise TypeError(
            "Cannot call select_related() after .values() or .values_list()"
        )

    obj = self._chain()
    if fields == (None,):
        obj.query.select_related = False
    elif fields:
        obj.query.add_select_related(fields)
    else:
        obj.query.select_related = True
    return obj

def get_initial_alias(self):
    """
    Return the first alias for this query, after increasing its reference
    count.
    """
    if self.alias_map:
        alias = self.base_table
        self.ref_alias(alias)
    elif self.model:
        alias = self.join(self.base_table_class(self.get_meta().db_table, None))
    else:
        alias = None
    return alias

def get_latest_lastmod(self):
    if self.date_field is not None:
        return (
            self.queryset.order_by("-" + self.date_field)
            .values_list(self.date_field, flat=True)
            .first()
        )
    return None

def index(
    request,
    sitemaps,
    template_name="sitemap_index.xml",
    content_type="application/xml",
    sitemap_url_name="django.contrib.sitemaps.views.sitemap",
):

    req_protocol = request.scheme
    req_site = get_current_site(request)

    sites = []  # all sections' sitemap URLs
    all_indexes_lastmod = True
    latest_lastmod = None
    for section, site in sitemaps.items():
        # For each section label, add links of all pages of its sitemap
        # (usually generated by the `sitemap` view).
        if callable(site):
            site = site()
        protocol = req_protocol if site.protocol is None else site.protocol
        sitemap_url = reverse(sitemap_url_name, kwargs={"section": section})
        absolute_url = "%s://%s%s" % (protocol, req_site.domain, sitemap_url)
        site_lastmod = site.get_latest_lastmod()
        if all_indexes_lastmod:
            if site_lastmod is not None:
                latest_lastmod = _get_latest_lastmod(latest_lastmod, site_lastmod)
            else:
                all_indexes_lastmod = False
        sites.append(SitemapIndexItem(absolute_url, site_lastmod))
        # Add links to all pages of the sitemap.
        for page in range(2, site.paginator.num_pages + 1):
            sites.append(
                SitemapIndexItem("%s?p=%s" % (absolute_url, page), site_lastmod)
            )
    # If lastmod is defined for all sites, set header so as
    # ConditionalGetMiddleware is able to send 304 NOT MODIFIED
    if all_indexes_lastmod and latest_lastmod:
        headers = {"Last-Modified": http_date(latest_lastmod.timestamp())}
    else:
        headers = None
    return TemplateResponse(
        request,
        template_name,
        {"sitemaps": sites},
        content_type=content_type,
        headers=headers,
    )

def _get_latest_lastmod(current_lastmod, new_lastmod):
    """
    Returns the latest `lastmod` where `lastmod` can be either a date or a
    datetime.
    """
    if not isinstance(new_lastmod, datetime.datetime):
        new_lastmod = datetime.datetime.combine(new_lastmod, datetime.time.min)
    if timezone.is_naive(new_lastmod):
        new_lastmod = timezone.make_aware(new_lastmod, datetime.timezone.utc)
    return new_lastmod if current_lastmod is None else max(current_lastmod, new_lastmod)

def items(self):
    # Make sure to return a clone; we don't want premature evaluation.
    return self.queryset.filter()

def sitemap(
    request,
    sitemaps,
    section=None,
    template_name="sitemap.xml",
    content_type="application/xml",
):

    req_protocol = request.scheme
    req_site = get_current_site(request)

    if section is not None:
        if section not in sitemaps:
            raise Http404("No sitemap available for section: %r" % section)
        maps = [sitemaps[section]]
    else:
        maps = sitemaps.values()
    page = request.GET.get("p", 1)

    lastmod = None
    all_sites_lastmod = True
    urls = []
    for site in maps:
        try:
            if callable(site):
                site = site()
            urls.extend(site.get_urls(page=page, site=req_site, protocol=req_protocol))
            if all_sites_lastmod:
                site_lastmod = getattr(site, "latest_lastmod", None)
                if site_lastmod is not None:
                    lastmod = _get_latest_lastmod(lastmod, site_lastmod)
                else:
                    all_sites_lastmod = False
        except EmptyPage:
            raise Http404("Page %s empty" % page)
        except PageNotAnInteger:
            raise Http404("No page '%s'" % page)
    # If lastmod is defined for all sites, set header so as
    # ConditionalGetMiddleware is able to send 304 NOT MODIFIED
    if all_sites_lastmod:
        headers = {"Last-Modified": http_date(lastmod.timestamp())} if lastmod else None
    else:
        headers = None
    return TemplateResponse(
        request,
        template_name,
        {"urlset": urls},
        content_type=content_type,
        headers=headers,
    )

def _items(self):
    if self.i18n:
        # Create (item, lang_code) tuples for all items and languages.
        # This is necessary to paginate with all languages already considered.
        items = [
            (item, lang_code)
            for lang_code in self._languages()
            for item in self.items()
        ]
        return items
    return self.items()

def _get(self, name, item, default=None):
    try:
        attr = getattr(self, name)
    except AttributeError:
        return default
    if callable(attr):
        if self.i18n:
            # Split the (item, lang_code) tuples again for the location,
            # priority, lastmod and changefreq method calls.
            item, lang_code = item
        return attr(item)
    return attr

def _location(self, item, force_lang_code=None):
    if self.i18n:
        obj, lang_code = item
        # Activate language from item-tuple or forced one before calling location.
        with translation.override(force_lang_code or lang_code):
            return self._get("location", item)
    return self._get("location", item)

def get_transformed_clip_path_and_affine(self):
