def run(self, mod: ast.Module) -> None:
    """Find all assert statements in *mod* and rewrite them."""
    if not mod.body:
        # Nothing to do.
        return

    # We'll insert some special imports at the top of the module, but after any
    # docstrings and __future__ imports, so first figure out where that is.
    doc = getattr(mod, "docstring", None)
    expect_docstring = doc is None
    if doc is not None and self.is_rewrite_disabled(doc):
        return
    pos = 0
    item = None
    for item in mod.body:
        if (
            expect_docstring
            and isinstance(item, ast.Expr)
            and isinstance(item.value, ast.Constant)
        ):
            doc = item.value.value
            if self.is_rewrite_disabled(doc):
                return
            expect_docstring = False
        elif (
            isinstance(item, ast.ImportFrom)
            and item.level == 0
            and item.module == "__future__"
        ):
            pass
        else:
            break
        pos += 1
    # Special case: for a decorated function, set the lineno to that of the
    # first decorator, not the `def`. Issue #4984.
    if isinstance(item, ast.FunctionDef) and item.decorator_list:
        lineno = item.decorator_list[0].lineno
    else:
        lineno = item.lineno
    # Now actually insert the special imports.
    if sys.version_info >= (3, 10):
        aliases = [
            ast.alias("builtins", "@py_builtins", lineno=lineno, col_offset=0),
            ast.alias(
                "_pytest.assertion.rewrite",
                "@pytest_ar",
                lineno=lineno,
                col_offset=0,
            ),
        ]
    else:
        aliases = [
            ast.alias("builtins", "@py_builtins"),
            ast.alias("_pytest.assertion.rewrite", "@pytest_ar"),
        ]
    imports = [
        ast.Import([alias], lineno=lineno, col_offset=0) for alias in aliases
    ]
    mod.body[pos:pos] = imports

    # Collect asserts.
    nodes: List[ast.AST] = [mod]
    while nodes:
        node = nodes.pop()
        for name, field in ast.iter_fields(node):
            if isinstance(field, list):
                new: List[ast.AST] = []
                for i, child in enumerate(field):
                    if isinstance(child, ast.Assert):
                        # Transform assert.
                        new.extend(self.visit(child))
                    else:
                        new.append(child)
                        if isinstance(child, ast.AST):
                            nodes.append(child)
                setattr(node, name, new)
            elif (
                isinstance(field, ast.AST)
                # Don't recurse into expressions as they can't contain
                # asserts.
                and not isinstance(field, ast.expr)
            ):
                nodes.append(field)

def _importtestmodule(self):
    # We assume we are only called once per module.
    importmode = self.config.getoption("--import-mode")
    try:
        mod = import_path(self.path, mode=importmode, root=self.config.rootpath)
    except SyntaxError as e:
        raise self.CollectError(
            ExceptionInfo.from_current().getrepr(style="short")
        ) from e
    except ImportPathMismatchError as e:
        raise self.CollectError(
            "import file mismatch:\n"
            "imported module %r has this __file__ attribute:\n"
            "  %s\n"
            "which is not the same as the test file we want to collect:\n"
            "  %s\n"
            "HINT: remove __pycache__ / .pyc files and/or use a "
            "unique basename for your test file modules" % e.args
        ) from e
    except ImportError as e:
        exc_info = ExceptionInfo.from_current()
        if self.config.getoption("verbose") < 2:
            exc_info.traceback = exc_info.traceback.filter(filter_traceback)
        exc_repr = (
            exc_info.getrepr(style="short")
            if exc_info.traceback
            else exc_info.exconly()
        )
        formatted_tb = str(exc_repr)
        raise self.CollectError(
            "ImportError while importing test module '{path}'.\n"
            "Hint: make sure your test modules/packages have valid Python names.\n"
            "Traceback:\n"
            "{traceback}".format(path=self.path, traceback=formatted_tb)
        ) from e
    except skip.Exception as e:
        if e.allow_module_level:
            raise
        raise self.CollectError(
            "Using pytest.skip outside of a test will skip the entire module. "
            "If that's your intention, pass `allow_module_level=True`. "
            "If you want to skip a specific test or an entire class, "
            "use the @pytest.mark.skip or @pytest.mark.skipif decorators."
        ) from e
    self.config.pluginmanager.consider_module(mod)
    return mod

def _inject_setup_module_fixture(self) -> None:
    """Inject a hidden autouse, module scoped fixture into the collected module object
    that invokes setUpModule/tearDownModule if either or both are available.

    Using a fixture to invoke this methods ensures we play nicely and unsurprisingly with
    other fixtures (#517).
    """
    has_nose = self.config.pluginmanager.has_plugin("nose")
    setup_module = _get_first_non_fixture_func(
        self.obj, ("setUpModule", "setup_module")
    )
    if setup_module is None and has_nose:
        # The name "setup" is too common - only treat as fixture if callable.
        setup_module = _get_first_non_fixture_func(self.obj, ("setup",))
        if not callable(setup_module):
            setup_module = None
    teardown_module = _get_first_non_fixture_func(
        self.obj, ("tearDownModule", "teardown_module")
    )
    if teardown_module is None and has_nose:
        teardown_module = _get_first_non_fixture_func(self.obj, ("teardown",))
        # Same as "setup" above - only treat as fixture if callable.
        if not callable(teardown_module):
            teardown_module = None

    if setup_module is None and teardown_module is None:
        return

    @fixtures.fixture(
        autouse=True,
        scope="module",
        # Use a unique name to speed up lookup.
        name=f"_xunit_setup_module_fixture_{self.obj.__name__}",
    )
    def xunit_setup_module_fixture(request) -> Generator[None, None, None]:
        if setup_module is not None:
            _call_with_optional_argument(setup_module, request.module)
        yield
        if teardown_module is not None:
            _call_with_optional_argument(teardown_module, request.module)

    self.obj.__pytest_setup_module = xunit_setup_module_fixture

def _inject_setup_function_fixture(self) -> None:
    """Inject a hidden autouse, function scoped fixture into the collected module object
    that invokes setup_function/teardown_function if either or both are available.

    Using a fixture to invoke this methods ensures we play nicely and unsurprisingly with
    other fixtures (#517).
    """
    setup_function = _get_first_non_fixture_func(self.obj, ("setup_function",))
    teardown_function = _get_first_non_fixture_func(
        self.obj, ("teardown_function",)
    )
    if setup_function is None and teardown_function is None:
        return

    @fixtures.fixture(
        autouse=True,
        scope="function",
        # Use a unique name to speed up lookup.
        name=f"_xunit_setup_function_fixture_{self.obj.__name__}",
    )
    def xunit_setup_function_fixture(request) -> Generator[None, None, None]:
        if request.instance is not None:
            # in this case we are bound to an instance, so we need to let
            # setup_method handle this
            yield
            return
        if setup_function is not None:
            _call_with_optional_argument(setup_function, request.function)
        yield
        if teardown_function is not None:
            _call_with_optional_argument(teardown_function, request.function)

    self.obj.__pytest_setup_function = xunit_setup_function_fixture

def repr(self, x: Any) -> str:
    try:
        s = super().repr(x)
    except (KeyboardInterrupt, SystemExit):
        raise
    except BaseException as exc:
        s = _format_repr_exception(exc, x)
    return _ellipsize(s, self.maxsize)

def _format_repr_exception(exc: BaseException, obj: Any) -> str:
    try:
        exc_info = _try_repr_or_str(exc)
    except (KeyboardInterrupt, SystemExit):
        raise
    except BaseException as exc:
        exc_info = "unpresentable exception ({})".format(_try_repr_or_str(exc))
    return "<[{} raised in repr()] {} object at 0x{:x}>".format(
        exc_info, obj.__class__.__name__, id(obj)
    )

def _try_repr_or_str(obj):
    try:
        return repr(obj)
    except (KeyboardInterrupt, SystemExit):
        raise
    except BaseException:
        return '{}("{}")'.format(type(obj).__name__, obj)

def repr_excinfo(self, excinfo: ExceptionInfo) -> "ExceptionChainRepr":
    repr_chain = (
        []
    )  # type: List[Tuple[ReprTraceback, Optional[ReprFileLocation], Optional[str]]]
    e = excinfo.value
    excinfo_ = excinfo  # type: Optional[ExceptionInfo]
    descr = None
    seen = set()  # type: Set[int]
    while e is not None and id(e) not in seen:
        seen.add(id(e))
        if excinfo_:
            reprtraceback = self.repr_traceback(excinfo_)
            reprcrash = excinfo_._getreprcrash()  # type: Optional[ReprFileLocation]
        else:
            # fallback to native repr if the exception doesn't have a traceback:
            # ExceptionInfo objects require a full traceback to work
            reprtraceback = ReprTracebackNative(
                traceback.format_exception(type(e), e, None)
            )
            reprcrash = None

        repr_chain += [(reprtraceback, reprcrash, descr)]
        if e.__cause__ is not None and self.chain:
            e = e.__cause__
            excinfo_ = (
                ExceptionInfo((type(e), e, e.__traceback__))
                if e.__traceback__
                else None
            )
            descr = "The above exception was the direct cause of the following exception:"
        elif (
            e.__context__ is not None and not e.__suppress_context__ and self.chain
        ):
            e = e.__context__
            excinfo_ = (
                ExceptionInfo((type(e), e, e.__traceback__))
                if e.__traceback__
                else None
            )
            descr = "During handling of the above exception, another exception occurred:"
        else:
            e = None
    repr_chain.reverse()
    return ExceptionChainRepr(repr_chain)

def repr_traceback(self, excinfo: ExceptionInfo) -> "ReprTraceback":
    traceback = excinfo.traceback
    if self.tbfilter:
        traceback = traceback.filter()

    if excinfo.errisinstance(RecursionError):
        traceback, extraline = self._truncate_recursive_traceback(traceback)
    else:
        extraline = None

    last = traceback[-1]
    entries = []
    for index, entry in enumerate(traceback):
        einfo = (last == entry) and excinfo or None
        reprentry = self.repr_traceback_entry(entry, einfo)
        entries.append(reprentry)
    return ReprTraceback(entries, extraline, style=self.style)

def repr_traceback_entry(
    self, entry: TracebackEntry, excinfo: Optional[ExceptionInfo] = None
) -> "ReprEntry":
    import _pytest._code

    source = self._getentrysource(entry)
    if source is None:
        source = _pytest._code.Source("???")
        line_index = 0
    else:
        line_index = entry.lineno - entry.getfirstlinesource()

    lines = []  # type: List[str]
    style = entry._repr_style if entry._repr_style is not None else self.style
    if style in ("short", "long"):
        short = style == "short"
        reprargs = self.repr_args(entry) if not short else None
        s = self.get_source(source, line_index, excinfo, short=short)
        lines.extend(s)
        if short:
            message = "in %s" % (entry.name)
        else:
            message = excinfo and excinfo.typename or ""
        path = self._makepath(entry.path)
        reprfileloc = ReprFileLocation(path, entry.lineno + 1, message)
        localsrepr = self.repr_locals(entry.locals)
        return ReprEntry(lines, reprargs, localsrepr, reprfileloc, style)
    if excinfo:
        lines.extend(self.get_exconly(excinfo, indent=4))
    return ReprEntry(lines, None, None, None, style)

def _hstack(self, Xs):
    """Stacks Xs horizontally.

    This allows subclasses to control the stacking behavior, while reusing
    everything else from ColumnTransformer.

    Parameters
    ----------
    Xs : list of {array-like, sparse matrix, dataframe}
    """
    if self.sparse_output_:
        try:
            # since all columns should be numeric before stacking them
            # in a sparse matrix, `check_array` is used for the
            # dtype conversion if necessary.
            converted_Xs = [
                check_array(X, accept_sparse=True, force_all_finite=False)
                for X in Xs
            ]
        except ValueError as e:
            raise ValueError(
                "For a sparse output, all columns should "
                "be a numeric or convertible to a numeric."
            ) from e

        return sparse.hstack(converted_Xs).tocsr()
    else:
        Xs = [f.toarray() if sparse.issparse(f) else f for f in Xs]
        config = _get_output_config("transform", self)
        if config["dense"] == "pandas" and all(hasattr(X, "iloc") for X in Xs):
            pd = check_pandas_support("transform")
            output = pd.concat(Xs, axis=1)

            # If all transformers define `get_feature_names_out`, then transform
            # will adjust the column names to be consistent with
            # verbose_feature_names_out. Here we prefix the feature names if
            # verbose_feature_names_out=True.

            if not self.verbose_feature_names_out:
                return output

            transformer_names = [
                t[0] for t in self._iter(fitted=True, replace_strings=True)
            ]
            feature_names_outs = [X.columns for X in Xs]
            names_out = self._add_prefix_for_feature_names_out(
                list(zip(transformer_names, feature_names_outs))
            )
            output.columns = names_out
            return output

        return np.hstack(Xs)

def _add_prefix_for_feature_names_out(self, transformer_with_feature_names_out):
    """Add prefix for feature names out that includes the transformer names.

    Parameters
    ----------
    transformer_with_feature_names_out : list of tuples of (str, array-like of str)
        The tuple consistent of the transformer's name and its feature names out.

    Returns
    -------
    feature_names_out : ndarray of shape (n_features,), dtype=str
        Transformed feature names.
    """
    if self.verbose_feature_names_out:
        # Prefix the feature names out with the transformers name
        names = list(
            chain.from_iterable(
                (f"{name}__{i}" for i in feature_names_out)
                for name, feature_names_out in transformer_with_feature_names_out
            )
        )
        return np.asarray(names, dtype=object)

    # verbose_feature_names_out is False
    # Check that names are all unique without a prefix
    feature_names_count = Counter(
        chain.from_iterable(s for _, s in transformer_with_feature_names_out)
    )
    top_6_overlap = [
        name for name, count in feature_names_count.most_common(6) if count > 1
    ]
    top_6_overlap.sort()
    if top_6_overlap:
        if len(top_6_overlap) == 6:
            # There are more than 5 overlapping names, we only show the 5
            # of the feature names
            names_repr = str(top_6_overlap[:5])[:-1] + ", ...]"
        else:
            names_repr = str(top_6_overlap)
        raise ValueError(
            f"Output feature names: {names_repr} are not unique. Please set "
            "verbose_feature_names_out=True to add prefixes to feature names"
        )

    return np.concatenate(
        [name for _, name in transformer_with_feature_names_out],
    )

def _iter(self, fitted=False, replace_strings=False, column_as_strings=False):
    """
    Generate (name, trans, column, weight) tuples.

    If fitted=True, use the fitted transformers, else use the
    user specified transformers updated with converted column names
    and potentially appended with transformer for remainder.

    """
    if fitted:
        if replace_strings:
            # Replace "passthrough" with the fitted version in
            # _name_to_fitted_passthrough
            def replace_passthrough(name, trans, columns):
                if name not in self._name_to_fitted_passthrough:
                    return name, trans, columns
                return name, self._name_to_fitted_passthrough[name], columns

            transformers = [
                replace_passthrough(*trans) for trans in self.transformers_
            ]
        else:
            transformers = self.transformers_
    else:
        # interleave the validated column specifiers
        transformers = [
            (name, trans, column)
            for (name, trans, _), column in zip(self.transformers, self._columns)
        ]
        # add transformer tuple for remainder
        if self._remainder[2]:
            transformers = chain(transformers, [self._remainder])
    get_weight = (self.transformer_weights or {}).get

    output_config = _get_output_config("transform", self)
    for name, trans, columns in transformers:
        if replace_strings:
            # replace 'passthrough' with identity transformer and
            # skip in case of 'drop'
            if trans == "passthrough":
                trans = FunctionTransformer(
                    accept_sparse=True,
                    check_inverse=False,
                    feature_names_out="one-to-one",
                ).set_output(transform=output_config["dense"])
            elif trans == "drop":
                continue
            elif _is_empty_column_selection(columns):
                continue

        if column_as_strings:
            # Convert all columns to using their string labels
            columns_is_scalar = np.isscalar(columns)

            indices = self._transformer_to_input_indices[name]
            columns = self.feature_names_in_[indices]

            if columns_is_scalar:
                # selection is done with one dimension
                columns = columns[0]

        yield (name, trans, columns, get_weight(name))

